import React, { useState, useEffect } from 'react';
import axios from 'axios';
// ADDED 'Plus' to the imports below to fix your error
import { 
  LogIn, UserPlus, ShieldCheck, FileText, CheckCircle, 
  X, LogOut, ArrowRight, Activity, Upload, Clock, Info, Plus 
} from 'lucide-react';

const Login = () => {
  const [view, setView] = useState('landing'); 
  const [activeTab, setActiveTab] = useState('services'); 
  const [formData, setFormData] = useState({ name: '', email: '', password: '' });
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [showModal, setShowModal] = useState(false);
  const [userRequests, setUserRequests] = useState([]); 
  const [isLoading, setIsLoading] = useState(false);

  const services = [
    { id: 1, title: 'Medical License Renewal', desc: 'Full handling of state board paperwork and fee management.', time: '15-30 Days' },
    { id: 2, title: 'Insurance Enrollment', desc: 'Get paneled with major payers like BlueCross, Aetna, and Cigna.', time: '60-90 Days' },
    { id: 3, title: 'DEA Certification', desc: 'Federal registration and compliance check for controlled substances.', time: '7 Days' }
  ];

  useEffect(() => {
    const token = localStorage.getItem('token');
    const userId = localStorage.getItem('userId');
    if (token) {
      setIsLoggedIn(true);
      setView('dashboard');
      if (userId) {
        axios.get(`http://localhost:5000/api/requests/user/${userId}`)
          .then(res => setUserRequests(res.data))
          .catch(err => console.log("Fetch error:", err));
      }
    }
  }, [isLoggedIn]);

  const handleAuth = async (e) => {
    e.preventDefault();
    setIsLoading(true);
    const mode = view === 'register' ? 'register' : 'login';
    try {
      const res = await axios.post(`http://localhost:5000/api/auth/${mode}`, formData);
      if (mode === 'login') {
        localStorage.setItem('token', res.data.token);
        localStorage.setItem('userId', res.data.user._id);
        localStorage.setItem('userName', res.data.user.name);
        setIsLoggedIn(true);
        setView('dashboard');
      } else {
        alert("Account Created! Please Sign In.");
        setView('login');
      }
    } catch (err) {
      alert(err.response?.data?.msg || "Authentication Failed");
    }
    setIsLoading(false);
  };

  const handleCredentialSubmit = async (e) => {
    e.preventDefault();
    const userId = localStorage.getItem('userId');
    const userName = localStorage.getItem('userName');
    
    const requestBody = {
      userId,
      userName,
      type: e.target[0].value,
      licenseNumber: e.target[1].value,
    };

    try {
      const res = await axios.post('http://localhost:5000/api/requests/submit', requestBody);
      setUserRequests([res.data.request, ...userRequests]);
      setShowModal(false);
      alert("✅ Request Submitted Successfully!");
      setActiveTab('tracking'); 
    } catch (err) {
      alert("Submission Failed. Make sure your server is running.");
    }
  };

  const handleLogout = () => {
    localStorage.clear();
    setIsLoggedIn(false);
    setView('landing');
    window.location.reload();
  };

  if (view === 'landing') {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6">
        <div className="text-center mb-12">
           <div className="inline-block bg-blue-600 p-4 rounded-3xl mb-4 text-white shadow-xl shadow-blue-200">
              <ShieldCheck size={48} />
           </div>
           <h1 className="text-5xl font-black text-slate-900 tracking-tight mb-2 italic">QUAD SOLUTIONS</h1>
           <p className="text-slate-500 font-medium text-lg text-center">Credentialing & Compliance for Modern Providers</p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8 max-w-4xl w-full">
          <div onClick={() => setView('register')} className="bg-white p-10 rounded-[3rem] shadow-xl border-2 border-transparent hover:border-blue-600 cursor-pointer transition group">
             <div className="w-16 h-16 bg-blue-50 rounded-2xl flex items-center justify-center mb-6 text-blue-600 group-hover:scale-110 transition"><UserPlus size={32} /></div>
             <h2 className="text-2xl font-black text-slate-800 mb-2">New Providers</h2>
             <p className="text-slate-500 mb-6">Start your registration and credentialing process today.</p>
             <div className="flex items-center text-blue-600 font-bold group-hover:gap-2 transition-all">Get Started <ArrowRight size={20} className="ml-2" /></div>
          </div>
          <div onClick={() => setView('login')} className="bg-slate-900 p-10 rounded-[3rem] shadow-xl border-2 border-transparent hover:border-blue-400 cursor-pointer transition group text-white">
             <div className="w-16 h-16 bg-white/10 rounded-2xl flex items-center justify-center mb-6 text-blue-400 group-hover:scale-110 transition"><LogIn size={32} /></div>
             <h2 className="text-2xl font-black mb-2">Existing Clients</h2>
             <p className="text-slate-300/70 mb-6">Manage your licenses and track existing requests.</p>
             <div className="flex items-center text-blue-400 font-bold group-hover:gap-2 transition-all">Sign In <ArrowRight size={20} className="ml-2" /></div>
          </div>
        </div>
      </div>
    );
  }

  if (view === 'login' || view === 'register') {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-6">
        <div className="w-full max-w-md bg-white p-10 rounded-[3rem] shadow-2xl relative">
          <button onClick={() => setView('landing')} className="absolute top-8 right-8 text-slate-300 hover:text-slate-600 font-bold">Back</button>
          <h2 className="text-4xl font-black mb-8 text-slate-900">{view === 'login' ? 'Login' : 'Register'}</h2>
          <form onSubmit={handleAuth} className="space-y-4">
            {view === 'register' && (
              <input type="text" placeholder="Full Name" className="w-full p-4 bg-slate-50 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500" onChange={(e) => setFormData({...formData, name: e.target.value})} required />
            )}
            <input type="email" placeholder="Email Address" className="w-full p-4 bg-slate-50 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500" onChange={(e) => setFormData({...formData, email: e.target.value})} required />
            <input type="password" placeholder="Password" className="w-full p-4 bg-slate-50 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500" onChange={(e) => setFormData({...formData, password: e.target.value})} required />
            <button disabled={isLoading} className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black text-lg shadow-lg hover:bg-blue-700 transition">
              {isLoading ? "Connecting..." : (view === 'login' ? 'Sign In' : 'Join Now')}
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <nav className="bg-white shadow-sm p-4 sticky top-0 z-50 border-b">
        <div className="max-w-7xl mx-auto flex justify-between items-center">
          <h1 className="text-xl font-black text-blue-600 tracking-tight italic">QUAD SOLUTIONS</h1>
          <div className="flex gap-6 items-center">
             <button onClick={() => setActiveTab('services')} className={`text-sm font-bold ${activeTab === 'services' ? 'text-blue-600' : 'text-slate-400'}`}>Services</button>
             <button onClick={() => setActiveTab('tracking')} className={`text-sm font-bold ${activeTab === 'tracking' ? 'text-blue-600' : 'text-slate-400'}`}>Tracking</button>
             <button onClick={handleLogout} className="text-red-500 font-bold"><LogOut size={20}/></button>
          </div>
        </div>
      </nav>

      <main className="p-6 md:p-10 max-w-7xl mx-auto w-full">
        {activeTab === 'services' ? (
          <section className="animate-in fade-in duration-500">
             <h2 className="text-3xl font-black text-slate-900 mb-8 text-center md:text-left">Select a Service</h2>
             <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                {services.map((service) => (
                  <div key={service.id} className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 hover:-translate-y-2 transition duration-300">
                    <div className="w-12 h-12 bg-blue-50 rounded-xl flex items-center justify-center mb-4 text-blue-600"><FileText/></div>
                    <h3 className="text-xl font-bold mb-2">{service.title}</h3>
                    <p className="text-slate-400 text-sm mb-6">{service.desc}</p>
                    <button onClick={() => setShowModal(true)} className="w-full bg-blue-600 text-white py-3 rounded-xl font-bold hover:bg-blue-700 transition">Apply Now</button>
                  </div>
                ))}
             </div>
          </section>
        ) : (
          <section className="animate-in fade-in duration-500">
             <h2 className="text-3xl font-black mb-8">Submission Tracking</h2>
             <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-100 overflow-hidden">
                {userRequests.length === 0 ? (
                  <div className="p-10 text-center text-slate-400 italic">No requests found. Start an application in Services.</div>
                ) : (
                  <div className="divide-y divide-slate-50">
                    {userRequests.map(req => (
                      <div key={req._id} className="p-6 flex justify-between items-center hover:bg-slate-50 transition">
                         <div>
                            <p className="font-bold text-slate-800">{req.type}</p>
                            <p className="text-xs text-slate-400">License ID: {req.licenseNumber} • {new Date(req.submittedDate).toLocaleDateString()}</p>
                         </div>
                         <div className={`px-4 py-1 rounded-full text-[10px] font-black uppercase ${req.status === 'Approved' ? 'bg-green-100 text-green-600' : 'bg-yellow-100 text-yellow-600'}`}>
                            {req.status}
                         </div>
                      </div>
                    ))}
                  </div>
                )}
             </div>
          </section>
        )}
      </main>

      {showModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md flex items-center justify-center p-4 z-[100]">
          <div className="bg-white w-full max-w-md rounded-[3rem] shadow-2xl p-10 animate-in zoom-in duration-200">
            <h2 className="text-2xl font-bold mb-6 flex items-center gap-2 text-blue-600"><Plus/> New Request</h2>
            <form onSubmit={handleCredentialSubmit} className="space-y-4">
              <div className="space-y-1">
                <label className="text-xs font-bold text-slate-400 uppercase">Service Category</label>
                <select className="w-full p-4 bg-slate-50 rounded-2xl border-none font-medium">
                  <option>Medical License Renewal</option>
                  <option>Insurance Panel Enrollment</option>
                  <option>DEA Certification</option>
                </select>
              </div>
              <div className="space-y-1">
                <label className="text-xs font-bold text-slate-400 uppercase">License / NPI Number</label>
                <input type="text" placeholder="e.g. LIC-123456" className="w-full p-4 bg-slate-50 rounded-2xl border-none focus:ring-2 focus:ring-blue-500" required />
              </div>
              <div className="p-6 border-2 border-dashed border-slate-100 rounded-2xl text-center">
                 <Upload size={24} className="mx-auto mb-2 text-slate-300"/>
                 <p className="text-[10px] text-slate-400 font-bold">PDF, JPG or PNG accepted</p>
              </div>
              <button className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black shadow-xl shadow-blue-100 hover:bg-blue-700 transition">Submit to QuadSolutions</button>
              <button onClick={() => setShowModal(false)} type="button" className="w-full text-slate-300 font-bold text-sm">Cancel</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Login;
